Set-StrictMode -Version 2.0
function Invoke-GodModePathDoctor { param([string]$Project='.') $r=Initialize-GodModeStructure $Project; $p=Resolve-GodModeProjectPath $Project; $risks=@(); $non=[bool]($p.ToCharArray()|?{[int][char]$_ -gt 127}|select -First 1); if($non){$risks+='project_path_non_ascii'}; if($p -match ' '){$risks+='spaces_in_path'}; if($p -match '[()]'){$risks+='parentheses_in_path'}; if($p -match 'OneDrive'){$risks+='onedrive_sync_path'}; $h=@{schema_version=1;generated_at=Get-GodModeIso;project_path=$p;project_path_non_ascii=$non;spaces_in_critical_paths=($p -match ' ');parentheses_in_critical_paths=($p -match '[()]');onedrive_path=($p -match 'OneDrive');cloud_sync_path=($p -match 'OneDrive|Dropbox|Google Drive');unc_path=$p.StartsWith('\\');mapped_drive=($p -match '^[A-Za-z]:');long_path_risk=($p.Length -gt 180);repo_under_windowsapps=($p -match 'WindowsApps');repo_under_program_files=($p -match 'Program Files');protected_system_location=($p -match '\\Windows\\|\\Program Files');wsl_path=($p -match '^\\\\wsl');git_path_encoding_risk=$non;non_ascii_git_remote_url='unknown';risks=$risks;recommendation=if($risks.Count){'Continue MVP; consider ASCII-safe mirror only if path failures occur.'}else{'safe_enough'}}; Write-GodModeJsonAtomic (Join-GodModePath $r 'state/path-health.json') $h|Out-Null; $h }
